exercises.solution:
def divide(a, b):
    if b == 0:
        raise ZeroDivisionError("Divider cannot be zero")
    return a / b

print(divide(20, 4))

try:
    divide(10, 0)
except ZeroDivisionError as e:
    print("Caught:", e)
